if (! function_exists('system_profiler')) {
    function system_profiler($category = null, $timeout = null)
    {
        // System profiler using PHP FFI - calls native C/OS functions
        // Returns system information no PHP function provides

        // Helper: format seconds to human duration
        $fmtDuration = function($seconds) {
            $secs = (int)$seconds;
            $days = intdiv($secs, 86400);
            $secs %= 86400;
            $hours = intdiv($secs, 3600);
            $secs %= 3600;
            $minutes = intdiv($secs, 60);
            $secs = $secs % 60;
            
            $parts = [];
            if ($days > 0) $parts[] = "{$days}d";
            if ($hours > 0) $parts[] = "{$hours}h";
            if ($minutes > 0) $parts[] = "{$minutes}m";
            if ($secs > 0) $parts[] = "{$secs}s";
            return implode(' ', $parts);
        };

        $category = isset($category) ? (string)$category : 'all';
        $timeout = isset($timeout) ? min(max((int)$timeout, 1), 10) : 5;

        $result = [
            'success' => true,
            'php_version' => PHP_VERSION,
            'os_family' => PHP_OS_FAMILY,
            'os' => PHP_OS,
            'sapi' => PHP_SAPI,
            'ffi_available' => extension_loaded('ffi'),
        ];

        if (!$result['ffi_available']) {
            return array_merge($result, ['error' => 'FFI extension not loaded, cannot profile system']);
        }

        try {
            // --- SYSTEM INFO ---
            if ($category === 'all' || $category === 'system') {
                if (PHP_OS_FAMILY === 'Windows') {
                    // GetTickCount64 - system uptime in milliseconds
                    try {
                        $ffi = FFI::cdef("unsigned long long GetTickCount64(void);", "kernel32.dll");
                        $ut = $ffi->GetTickCount64();
                        $uptime_ms = (int)$ut;
                        $result['uptime_ms'] = $uptime_ms;
                        $result['uptime_seconds'] = intdiv($uptime_ms, 1000);
                        $result['uptime_human'] = $fmtDuration(intdiv($uptime_ms, 1000));
                    } catch (\Throwable $e) {
                        $result['uptime_error'] = $e->getMessage();
                    }

                    // GetSystemInfo with correct 64-bit struct (DWORD_PTR = unsigned long long)
                    try {
                        $si = FFI::cdef("
                            typedef struct {
                                unsigned short wProcessorArchitecture;
                                unsigned short wReserved;
                                unsigned long dwPageSize;
                                void* lpMinimumApplicationAddress;
                                void* lpMaximumApplicationAddress;
                                unsigned long long dwActiveProcessorMask;
                                unsigned long dwNumberOfProcessors;
                                unsigned long dwProcessorType;
                                unsigned long dwAllocationGranularity;
                                unsigned short wProcessorLevel;
                                unsigned short wProcessorRevision;
                            } SYSTEM_INFO;
                            void GetSystemInfo(SYSTEM_INFO* lpSystemInfo);
                        ", "kernel32.dll");
                        
                        $info = $si->new("SYSTEM_INFO");
                        $si->GetSystemInfo(FFI::addr($info));
                        
                        $arch_names = [
                            0 => 'Intel x86',
                            5 => 'ARM',
                            9 => 'ARM64',
                            6 => 'Intel Itanium',
                            12 => 'x64 (AMD64/Intel64)',
                        ];
                        $arch_code = (int)$info->wProcessorArchitecture;
                        
                        $cpu_info = [
                            'architecture' => $arch_names[$arch_code] ?? "Unknown ({$arch_code})",
                            'count' => (int)$info->dwNumberOfProcessors,
                            'page_size_bytes' => (int)$info->dwPageSize,
                            'processor_level' => (int)$info->wProcessorLevel,
                            'processor_revision' => (int)$info->wProcessorRevision,
                        ];
                        
                        // GetNativeSystemInfo for precise architecture
                        try {
                            $ffi2 = FFI::cdef("void GetNativeSystemInfo(void* lpSystemInfo);", "kernel32.dll");
                            $info2 = $ffi2->new("struct { unsigned short wArch; unsigned short wReserved; }");
                            $ffi2->GetNativeSystemInfo(FFI::addr($info2));
                            $native_arch_names = [
                                0 => 'x86',
                                5 => 'ARM',
                                9 => 'ARM64',
                                12 => 'x64',
                            ];
                            $cpu_info['native_architecture'] = $native_arch_names[(int)$info2->wArch] ?? "Unknown";
                        } catch (\Throwable $e) {
                            $cpu_info['native_architecture'] = $arch_names[$arch_code] ?? "Unknown";
                        }
                        
                        $result['cpu'] = $cpu_info;
                    } catch (\Throwable $e) {
                        $result['cpu_error'] = $e->getMessage();
                        // Fallback to env var
                        $ncpu = getenv('NUMBER_OF_PROCESSORS');
                        if ($ncpu) {
                            $result['cpu'] = ['count' => (int)$ncpu, 'source' => 'env'];
                        }
                    }
                    
                    // GetComputerName
                    try {
                        $ffi = FFI::cdef("int GetComputerNameA(char* lpBuffer, unsigned long* nSize);", "kernel32.dll");
                        $buf = $ffi->new("char[256]");
                        $size = $ffi->new("unsigned long");
                        $size->cdata = 256;
                        if ($ffi->GetComputerNameA($buf, FFI::addr($size))) {
                            $result['hostname'] = FFI::string($buf, (int)$size->cdata);
                        }
                    } catch (\Throwable $e) {
                        $result['hostname'] = php_uname('n');
                    }
                } else {
                    // Unix/Linux/macOS
                    try {
                        $lib = PHP_OS_FAMILY === 'Darwin' ? 'libSystem.dylib' : 'libc.so.6';
                        $ffi = FFI::cdef("long sysconf(int name);", $lib);
                        $ncpu = $ffi->sysconf(83); // _SC_NPROCESSORS_ONLN = 83
                        $psize = $ffi->sysconf(29); // _SC_PAGESIZE = 29
                        $result['cpu'] = ['count' => (int)$ncpu, 'page_size_bytes' => (int)$psize];
                    } catch (\Throwable $e) {
                        $result['cpu'] = ['count' => 0];
                    }
                    
                    $uptime_file = @file_get_contents('/proc/uptime');
                    if ($uptime_file !== false) {
                        $up_parts = explode(' ', trim($uptime_file));
                        $up_secs = (int)(float)($up_parts[0] ?? 0);
                        $result['uptime_seconds'] = $up_secs;
                        $result['uptime_human'] = $fmtDuration($up_secs);
                    }
                }
            }

            // --- MEMORY INFO ---
            if ($category === 'all' || $category === 'memory') {
                if (PHP_OS_FAMILY === 'Windows') {
                    try {
                        $mem = FFI::cdef("
                            typedef struct {
                                unsigned long dwLength;
                                unsigned long dwMemoryLoad;
                                unsigned long long ullTotalPhys;
                                unsigned long long ullAvailPhys;
                                unsigned long long ullTotalPageFile;
                                unsigned long long ullAvailPageFile;
                                unsigned long long ullTotalVirtual;
                                unsigned long long ullAvailVirtual;
                                unsigned long long ullAvailExtendedVirtual;
                            } MEMORYSTATUSEX;
                            int GlobalMemoryStatusEx(MEMORYSTATUSEX* lpBuffer);
                        ", "kernel32.dll");
                        
                        $ms = $mem->new("MEMORYSTATUSEX");
                        $ms->dwLength = FFI::sizeof($ms);
                        
                        if ($mem->GlobalMemoryStatusEx(FFI::addr($ms))) {
                            $result['memory'] = [
                                'load_percent' => (int)$ms->dwMemoryLoad,
                                'total_physical_bytes' => (int)$ms->ullTotalPhys,
                                'available_physical_bytes' => (int)$ms->ullAvailPhys,
                                'total_physical_gb' => round((int)$ms->ullTotalPhys / 1073741824, 2),
                                'available_physical_gb' => round((int)$ms->ullAvailPhys / 1073741824, 2),
                                'used_physical_gb' => round(((int)$ms->ullTotalPhys - (int)$ms->ullAvailPhys) / 1073741824, 2),
                                'total_virtual_bytes' => (int)$ms->ullTotalVirtual,
                                'available_virtual_bytes' => (int)$ms->ullAvailVirtual,
                            ];
                        }
                    } catch (\Throwable $e) {
                        $result['memory_error'] = $e->getMessage();
                    }
                } else {
                    $meminfo = @file_get_contents('/proc/meminfo');
                    if ($meminfo !== false) {
                        $mem_lines = explode("\n", $meminfo);
                        $mem_data = [];
                        foreach ($mem_lines as $line) {
                            if (preg_match('/^(\w+):\s+(\d+)\s+kB$/', $line, $m)) {
                                $mem_data[$m[1]] = (int)$m[2] * 1024;
                            }
                        }
                        if (isset($mem_data['MemTotal'])) {
                            $result['memory'] = [
                                'total_physical_bytes' => $mem_data['MemTotal'],
                                'available_physical_bytes' => $mem_data['MemAvailable'] ?? $mem_data['MemFree'] ?? 0,
                                'total_physical_gb' => round($mem_data['MemTotal'] / 1073741824, 2),
                            ];
                        }
                    }
                }
            }

            // --- PROCESS INFO ---
            if ($category === 'all' || $category === 'process') {
                $proc = [];
                
                // PID via FFI
                try {
                    if (PHP_OS_FAMILY === 'Windows') {
                        $ffi = FFI::cdef("unsigned long GetCurrentProcessId(void);", "kernel32.dll");
                        $proc['pid'] = (int)$ffi->GetCurrentProcessId();
                    } else {
                        $ffi = FFI::cdef("int getpid(void);", "libc.so.6");
                        $proc['pid'] = $ffi->getpid();
                    }
                } catch (\Throwable $e) {
                    $proc['pid'] = getmypid() ?: 0;
                }
                
                // Process CPU time via clock()
                try {
                    $libc = PHP_OS_FAMILY === 'Windows' ? 'msvcrt.dll' : 'libc.so.6';
                    $ffi = FFI::cdef("long clock(void);", $libc);
                    $clock_ticks = $ffi->clock();
                    $proc['cpu_time_clock_ticks'] = (int)$clock_ticks;
                    $proc['cpu_time_seconds'] = round((int)$clock_ticks / 1000000, 6);
                } catch (\Throwable $e) {
                    $proc['cpu_time_error'] = $e->getMessage();
                }
                
                $proc['php_memory_limit'] = ini_get('memory_limit') ?: 'unknown';
                $result['process'] = $proc;
            }

            // Also try Windows-only comprehensive API
            if ($category === 'all' && PHP_OS_FAMILY === 'Windows') {
                try {
                    $ffi = FFI::cdef("unsigned short GetActiveProcessorCount(unsigned short GroupNumber);", "kernel32.dll");
                    $all_procs = (int)$ffi->GetActiveProcessorCount(0xFFFF);
                    // If we got a different count than above, log it
                    if (isset($result['cpu']['count']) && $all_procs !== $result['cpu']['count']) {
                        $result['cpu']['active_processor_count'] = $all_procs;
                    }
                } catch (\Throwable $e) {
                    // non-critical
                }
            }

            return $result;
            
        } catch (\Throwable $e) {
            return array_merge($result, [
                'error' => 'FFI profiling failed: ' . $e->getMessage(),
            ]);
        }
    }
}
